export function drawCards(player: PlayerState, count: number, rng: Rng): CardId[] {
  const drawn: CardId[] = [];
  for (let drawnCount = 0; drawnCount < count; drawnCount += 1) {
    ensureDrawHasCards(player, rng);
    const card = player.draw.shift();
    if (card === undefined) {
